INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('ece56ca9-6585-4781-b2ef-78d75c20008b', 'Singapore', 'Southeast Asia', 'E-Visa Required', 'Mandatory e-Visa for Indian passport holders, no visa-on-arrival, no visa-free entry. ~INR 2,100-3,799 incl. agent fee, 3-5 working days processing via authorised agents (VFS Global, IVS Global). NOTE: earlier placeholder data in this project incorrectly listed ''Easy Visa'' - corrected here.', '2026-06-25', FALSE, 'SGD', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('d559a10c-2351-4866-b6c4-91ce501b1128', 'UAE', 'Middle East', 'E-Visa Required / Conditional VOA', 'Visa required in advance UNLESS traveller holds a valid US/UK/EU-Schengen/Australia/Canada/Japan/New Zealand/Korea/Singapore visa or residence permit (6+ months validity), in which case a 14-day visa-on-arrival applies (~AED 100-120). Otherwise standard e-Visa needed before travel.', '2026-06-25', FALSE, 'AED', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('5db45750-d14f-45e2-bd82-ada00e99ab96', 'Thailand', 'Southeast Asia', 'IN TRANSITION - Visa-on-Arrival (was Visa-Free)', 'VOLATILE, VERIFY BEFORE USE: As of this research (late May 2026), Thailand''s Cabinet approved ending the 60-day visa-free scheme for Indians, replacing it with a 15-day Visa-on-Arrival (~2,000 THB / ~INR 4,800-5,800). Change takes effect 15 days after Royal Gazette publication (not yet published at research time). Mandatory Thailand Digital Arrival Card (TDAC) regardless of visa status. DO NOT treat this field as stable - re-verify at implementation time.', '2026-06-25', TRUE, 'THB', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('572b8b86-01dc-4167-9229-850a6c471870', 'Indonesia', 'Southeast Asia', 'Visa on Arrival', '30-day VOA, extendable once for another 30 days. Cost approx. IDR 500,000 (~INR 2,600-2,800). Requires passport 6+ months validity and return ticket.', '2026-06-25', FALSE, 'IDR', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('0fd961b8-6e79-4fcf-9f25-fbc096608145', 'Maldives', 'South Asia/Indian Ocean', 'Visa-Free (Free VOA)', 'Free 30-day visa-on-arrival for all Indian passport holders. Requires return ticket, hotel/resort reservation, sufficient funds. Note: independent travel outside resort islands requires special permission.', '2026-06-25', FALSE, 'USD/MVR', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('93063aef-8350-406b-acef-df9c62d8d21b', 'Vietnam', 'Southeast Asia', 'E-Visa', '90-day e-Visa, single or multiple entry, ~USD 25. Apply only via official government e-visa portal (avoid third-party scam sites).', '2026-06-25', FALSE, 'VND', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('1bb977df-a543-4654-afe5-7e1a1ef428ff', 'Sri Lanka', 'South Asia', 'Visa-Free (Free ETA)', 'Free 30-day Electronic Travel Authorization for Indians. Sri Lanka announced expansion of visa-free access to 40 markets from Jan 2026, India already included under existing arrangement.', '2026-06-25', FALSE, 'LKR', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('08ed8c68-35a4-4812-9a1e-1a872aa6cc83', 'Malaysia', 'Southeast Asia', 'Visa-Free (Time-Limited Policy)', 'Visa-free for Indians for stays up to 30 days, in effect until 31 December 2026 per current policy - re-verify closer to/after that date. Mandatory Malaysia Digital Arrival Card (MDAC) online within 3 days of arrival.', '2026-06-25', TRUE, 'MYR', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('fb8afe69-11af-4d81-a706-cbab7bcae31c', 'Mauritius', 'Indian Ocean/Africa', 'Visa-Free', 'Visa-free entry for up to 90 days for Indian passport holders.', '2026-06-25', FALSE, 'MUR', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('52f012dc-a366-46e1-b33e-1048609b0a0a', 'Bhutan', 'South Asia', 'Visa-Free (SDF applies)', 'No visa required for Indian passport/voter-ID holders - unrestricted entry. IMPORTANT: a Sustainable Development Fee (SDF) applies per person per night for most travelers (concessional rate historically applied for Indian nationals) - exact current rate must be verified at implementation time, as Bhutan revises this periodically.', '2026-06-25', TRUE, 'BTN/INR', 'limited', FALSE);
INSERT INTO countries (id, name, region, visa_policy_default, visa_note, visa_last_verified, visa_volatile, currency, supplier_coverage_status, domestic_flag) VALUES ('cd1b3736-f9fa-4c4f-b362-c41d4948be62', 'India', 'West India', 'Domestic - No Visa Required', 'Domestic travel, no visa applicable.', '2026-06-25', FALSE, 'INR', 'limited', TRUE);
