-- Journey OS — Researched Destination & Package Data
-- Generated from real web research conducted 2026-06-25 (see RESEARCH_METHODOLOGY.md).
-- IMPORTANT: rows are flagged needs_owner_review = TRUE where applicable —
-- this is market-researched starting content, not confirmed sellable pricing.
-- Requires the Stage B schema (001-006 migrations) already applied, PLUS the
-- packages/package_components extension below (run that first if not present).

-- ============================================================
-- SCHEMA EXTENSION: packages + package_components
-- (per JourneyOS_Full_Product_Audit_Configurator_Strategy.md §7
--  and JourneyOS_Pivot_Addendum_2.md §B2)
-- ============================================================

ALTER TABLE countries ADD COLUMN IF NOT EXISTS visa_note text;
ALTER TABLE countries ADD COLUMN IF NOT EXISTS visa_last_verified date;
ALTER TABLE countries ADD COLUMN IF NOT EXISTS visa_volatile boolean NOT NULL DEFAULT false;
ALTER TABLE experiences ADD COLUMN IF NOT EXISTS needs_owner_review boolean NOT NULL DEFAULT true;

CREATE TABLE IF NOT EXISTS packages (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  destination_city_id uuid NOT NULL REFERENCES cities(id) ON DELETE CASCADE,
  duration_nights integer NOT NULL,
  package_tier text NOT NULL CHECK (package_tier IN ('comfort','premium','signature')),
  base_price numeric(12,2) NOT NULL,
  needs_owner_review boolean NOT NULL DEFAULT true,
  is_active boolean NOT NULL DEFAULT true,
  is_featured boolean NOT NULL DEFAULT false,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS package_components (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  package_id uuid NOT NULL REFERENCES packages(id) ON DELETE CASCADE,
  component_type text NOT NULL CHECK (component_type IN ('included_experience','hotel_upgrade','addon_experience','extra_day')),
  experience_id uuid REFERENCES experiences(id),
  price_delta numeric(12,2) NOT NULL DEFAULT 0
);

CREATE INDEX IF NOT EXISTS idx_packages_city ON packages(destination_city_id);
CREATE INDEX IF NOT EXISTS idx_package_components_package ON package_components(package_id);


